class GoogleCloudVisionApi {
  final String apiKey;
  final http.Client client;

  GoogleCloudVisionApi(this.apiKey, {http.Client? httpClient}) : client = httpClient ?? http.Client();

  Future<AnnotateImageResponse> annotateImage(ImageSource imageSource, {List<String>? features}) async {
    final url = 'https://vision.googleapis.com/v1/images:annotate?key=$apiKey';
    final request = {
      'requests': [
        {
          'image': {'source': _getImageSourceJson(imageSource)},
          'features': features?.map((feature) => {'type': feature}).toList() ?? []
        }
      ]
    };

    final response = await client.post(Uri.parse(url), body: jsonEncode(request), headers: {'Content-Type': 'application/json'});
    if (response.statusCode == 200) {
      return AnnotateImageResponse.fromJson(jsonDecode(response.body));
    } else {
      throw Exception('Failed to load data');
    }
  }

  Map<String, dynamic> _getImageSourceJson(ImageSource imageSource) {
    switch (imageSource.type) {
      case ImageSourceType.uri:
        return {'imageUri': imageSource.value};
      default:
        throw ArgumentError('Unsupported image source type');
    }
  }
}

